<?php if (!defined("ABSPATH")) exit; ?> <div class="wrap"> <h1><?php _e("Smart Chat Settings", "smart-chat"); ?></h1> <form method="post" action="options.php"> <?php settings_fields("hmsc_options"); ?> <table class="form-table"> <tr><th scope="row"><?php _e("Enable Chat", "smart-chat"); ?></th><td><input type="checkbox" name="hmsc_options[enable]" value="1" <?php checked(hmsc_get_option("enable", true)); ?> /></td></tr> <tr><th scope="row"><?php _e("Position", "smart-chat"); ?></th><td><select name="hmsc_options[position]"><option value="bottom-right" <?php selected(hmsc_get_option("position"), "bottom-right"); ?>><?php _e("Bottom Right", "smart-chat"); ?></option><option value="bottom-left" <?php selected(hmsc_get_option("position"), "bottom-left"); ?>><?php _e("Bottom Left", "smart-chat"); ?></option></select></td></tr> <tr><th scope="row"><?php _e("Welcome Text", "smart-chat"); ?></th><td><textarea name="hmsc_options[welcome_text]" rows="3" cols="50"><?php echo esc_textarea(hmsc_get_option("welcome_text")); ?></textarea></td></tr> <tr><th scope="row"><?php _e("Theme Color", "smart-chat"); ?></th><td><input type="color" name="hmsc_options[theme_color]" value="<?php echo esc_attr(hmsc_get_option("theme_color")); ?>" /></td></tr> </table> <?php submit_button(); ?> </form> </div>
